 1→import { useCallback, useMemo } from "react";
 2→import { useScrollToSelected } from "../hooks/useScrollToSelected";
 3→import { useAutoScroll } from "../hooks/useAutoScroll";
 4→import type { DisplayMessage } from "../types";
 5→import { MessageItem } from "./MessageItem";
 6→
 7→interface MessageListProps {
 8→  messages: DisplayMessage[];
 9→  selectedIndex: number;
10→  expandedSet: Set<number>;
11→  ongoing: boolean;
12→  onSelect: (index: number) => void;
13→  onToggle: (index: number) => void;
14→  onOpenDetail: (index: number) => void;
15→}
16→
17→export function MessageList({
18→  messages,
19→  selectedIndex,
20→  expandedSet,
21→  ongoing,
22→  onSelect,
23→  onToggle,
24→  onOpenDetail,
25→}: MessageListProps) {
26→  const listRef = useAutoScroll<HTMLDivElement>(messages.length);
27→  const selectedRef = useScrollToSelected(selectedIndex);
28→
29→  const handleClick = useCallback(
30→    (index: number) => {
31→      if (selectedIndex === index) {
32→        onToggle(index);
33→      } else {
34→        onSelect(index);
35→      }
36→    },
37→    [selectedIndex, onSelect, onToggle],
38→  );
39→
40→  // Chronological order: oldest messages first
41→  const ordered = useMemo(() => {
42→    const indices: number[] = [];
43→    for (let i = 0; i < messages.length; i++) {
44→      indices.push(i);
45→    }
46→    return indices;
47→  }, [messages.length]);
48→
49→  if (messages.length === 0) {
50→    return (
51→      <div className="message-list">
52→        <div className="message-list__empty">No messages loaded</div>
53→      </div>
54→    );
55→  }
56→
57→  return (
58→    <div className="message-list" ref={listRef}>
59→      {ordered.map((i) => {
60→        const msg = messages[i];
61→        if (msg.role === "compact") {
62→          return <CompactSeparator key={i} content={msg.content} />;
63→        }
64→
65→        const isSelected = i === selectedIndex;
66→        const isLast = i === messages.length - 1;
67→
68→        return (
69→          <MessageItem
70→            key={i}
71→            ref={isSelected ? selectedRef : undefined}
72→            message={msg}
73→            index={i}
74→            isSelected={isSelected}
75→            isExpanded={expandedSet.has(i)}
76→            onClick={handleClick}
77→            onOpenDetail={onOpenDetail}
78→            isOngoing={isLast && ongoing}
79→          />
80→        );
81→      })}
82→    </div>
83→  );
84→}
85→
86→function CompactSeparator({ content }: { content: string }) {
87→  return (
88→    <div className="compact-separator">
89→      <div className="compact-separator__line">
90→        <span className="compact-separator__rule" />
91→        <span>{content}</span>
92→        <span className="compact-separator__rule" />
93→      </div>
94→    </div>
95→  );
96→}
