  1→import type { TeamSnapshot } from "../types";
  2→import { getTeamColor } from "../lib/theme";
  3→import { BackButton } from "./BackButton";
  4→import { taskStatusIcons, ClaudeIcon, ForwardIcon } from "./Icons";
  5→
  6→interface TeamBoardProps {
  7→  teams: TeamSnapshot[];
  8→  onBack: () => void;
  9→}
 10→
 11→export function TeamBoard({ teams, onBack }: TeamBoardProps) {
 12→  // Filter out deleted teams
 13→  const activeTeams = teams.filter((t) => !t.deleted);
 14→
 15→  if (activeTeams.length === 0) {
 16→    return (
 17→      <div className="team-board">
 18→        <div className="team-board__header">
 19→          <BackButton onClick={onBack} />
 20→        </div>
 21→        <div className="empty-state">
 22→          <div className="empty-state__icon">
 23→            <ClaudeIcon />
 24→          </div>
 25→          <div className="empty-state__text">No active teams</div>
 26→        </div>
 27→      </div>
 28→    );
 29→  }
 30→
 31→  return (
 32→    <div className="team-board">
 33→      {activeTeams.map((team, teamIdx) => (
 34→        <div key={team.name || `team-${team.description}`}>
 35→          <div className="team-board__header">
 36→            {teamIdx === 0 && <BackButton onClick={onBack} />}
 37→            <div className="team-board__title">{team.name || "Team"}</div>
 38→            {team.description && <div className="team-board__desc">{team.description}</div>}
 39→          </div>
 40→
 41→          <div className="team-board__body">
 42→            {/* Members */}
 43→            {team.members.length > 0 && (
 44→              <div className="team-board__section">
 45→                <div className="team-board__section-title">Members ({team.members.length})</div>
 46→                <div>
 47→                  {team.members.map((member) => {
 48→                    const colorName = team.member_colors[member] ?? "";
