 175→// ---------------------------------------------------------------------------
 176→// OngoingChecker — determines whether a session (or subagent) is ongoing
 177→// ---------------------------------------------------------------------------
 178→
 179→/// Checks ongoing status by combining chunk analysis, subagent state, and file staleness.
 180→pub struct OngoingChecker<'a> {
 181→    chunks: &'a [Chunk],
 182→    procs: &'a [super::subagent::SubagentProcess],
 183→    session_path: &'a str,
 184→}
 185→
 186→impl<'a> OngoingChecker<'a> {
 187→    pub fn new(
 188→        chunks: &'a [Chunk],
 189→        procs: &'a [super::subagent::SubagentProcess],
 190→        session_path: &'a str,
 191→    ) -> Self {
 192→        Self {
 193→            chunks,
 194→            procs,
 195→            session_path,
 196→        }
 197→    }
 198→
 199→    /// Full ongoing check: chunks → subagents → background commands → file staleness.
 200→    pub fn is_ongoing(&self) -> bool {
 201→        let chunks_active = self.chunks_ongoing();
 202→        let subagents_active = self.any_subagent_ongoing();
 203→
 204→        if chunks_active {
 205→            // Main chunks show activity. If the main file is fresh, ongoing.
 206→            // If the main file is stale but a subagent is still fresh, also
 207→            // ongoing — the main file stops being written to while subagents
 208→            // do the actual work.
 209→            if self.is_file_fresh() || subagents_active {
 210→                return true;
 211→            }
 212→        }
 213→
 214→        // Subagent is active even though main chunks look done.
 215→        if subagents_active {
 216→            return true;
 217→        }
 218→
 219→        // Check for background Bash commands that haven't completed yet
 220→        // (in main session or subagent chunks — subagent check is inside
 221→        // is_subagent_ongoing above, this catches main-session-level ones).
 222→        Self::has_pending_background_commands(self.chunks)
 223→    }
 224→
 225→    /// Check if a subagent process is ongoing (chunk-based + background commands + file staleness).
 226→    pub fn is_subagent_ongoing(proc: &super::subagent::SubagentProcess) -> bool {
 227→        (Self::is_chunks_ongoing(&proc.chunks)
 228→            || Self::has_pending_background_commands(&proc.chunks))
 229→            && apply_staleness(true, proc.file_mod_time)
 230→    }
 231→
 232→    /// Cascading check: returns true if `proc` or any of its descendant subagents are ongoing.
 233→    pub fn is_subagent_ongoing_deep(
 234→        proc: &super::subagent::SubagentProcess,
 235→        all_procs: &[super::subagent::SubagentProcess],
 236→    ) -> bool {
 237→        if Self::is_subagent_ongoing(proc) {
 238→            return true;
 239→        }
 240→        // Collect tool_ids from this proc's chunks to find child processes.
 241→        let child_tool_ids: HashSet<&str> = proc
 242→            .chunks
 243→            .iter()
 244→            .flat_map(|c| c.items.iter())
 245→            .filter(|it| {
 246→                it.item_type == DisplayItemType::Subagent
 247→                    || ((it.tool_name == "Task" || it.tool_name == "Agent")
 248→                        && it.item_type == DisplayItemType::ToolCall)
 249→            })
 250→            .map(|it| it.tool_id.as_str())
 251→            .collect();
 252→        if child_tool_ids.is_empty() {
 253→            return false;
 254→        }
 255→        all_procs
 256→            .iter()
 257→            .filter(|p| child_tool_ids.contains(p.parent_task_id.as_str()))
 258→            .any(|p| Self::is_subagent_ongoing_deep(p, all_procs))
 259→    }
 260→
 261→    /// Reports whether the chunks indicate the session is still in progress.
 262→    pub fn is_chunks_ongoing(chunks: &[Chunk]) -> bool {
 263→        if chunks.is_empty() {
 264→            return false;
 265→        }
 266→
 267→        // Trailing user prompt means Claude is processing.
 268→        if chunks.last().map(|c| &c.chunk_type) == Some(&ChunkType::User) {
 269→            return true;
 270→        }
 271→
 272→        let activity_log = ActivityLog::from_chunks(chunks);
 273→
 274→        if activity_log.has_items {
 275→            if activity_log.is_ongoing() {
 276→                return true;
 277→            }
 278→            return Self::has_pending_agents(chunks);
 279→        }
 280→
 281→        // Fallback for old-style chunks.
 282→        for c in chunks.iter().rev() {
 283→            if c.chunk_type == ChunkType::AI {
 284→                return c.stop_reason != "end_turn";
 285→            }
 286→        }
 287→
 288→        false
 289→    }
 290→
 291→    // -- Private helpers --
 292→
 293→    fn chunks_ongoing(&self) -> bool {
 294→        Self::is_chunks_ongoing(self.chunks)
 295→    }
 296→
 297→    fn any_subagent_ongoing(&self) -> bool {
 298→        self.procs.iter().any(Self::is_subagent_ongoing)
 299→    }
 300→
 301→    fn is_file_fresh(&self) -> bool {
 302→        if let Ok(info) = std::fs::metadata(self.session_path) {
 303→            if let Ok(modified) = info.modified() {
 304→                return apply_staleness(true, modified);
 305→            }
 306→        }
 307→        true // If we can't read metadata, assume fresh
 308→    }
 309→
 310→    fn has_pending_agents(chunks: &[Chunk]) -> bool {
 311→        for chunk in chunks {
 312→            if chunk.chunk_type != ChunkType::AI {
 313→                continue;
 314→            }
 315→            for item in &chunk.items {
 316→                match item.item_type {
 317→                    DisplayItemType::Subagent => {
 318→                        if item.tool_result.is_empty() {
 319→                            return true;
 320→                        }
 321→                    }
 322→                    DisplayItemType::ToolCall => {
 323→                        if (item.tool_name == "Task" || item.tool_name == "Agent")
 324→                            && item.tool_result.is_empty()
 325→                        {
 326→                            return true;
 327→                        }
 328→                    }
 329→                    _ => {}
 330→                }
 331→            }
 332→        }
 333→        false
 334→    }
 335→
 336→    /// Check for Bash commands launched with run_in_background that haven't
 337→    /// received a terminal task notification yet (completed/failed/killed).
 338→    /// Counts background launches vs terminal notifications — if launches
 339→    /// exceed notifications, some commands are still running.
 340→    fn has_pending_background_commands(chunks: &[Chunk]) -> bool {
 341→        let mut bg_launched: usize = 0;
 342→        let mut bg_resolved: usize = 0;
 343→
 344→        for chunk in chunks {
 345→            match chunk.chunk_type {
 346→                ChunkType::AI => {
 347→                    for item in &chunk.items {
 348→                        if item.item_type == DisplayItemType::ToolCall
 349→                            && item.tool_result.contains("running in background")
 350→                        {
 351→                            bg_launched += 1;
 352→                        }
 353→                    }
 354→                }
 355→                ChunkType::System => {
 356→                    let out = &chunk.output;
 357→                    if (out.contains("completed")
 358→                        || out.contains("failed")
 359→                        || out.contains("was stopped"))
 360→                        && out.contains("Background command")
 361→                    {
 362→                        bg_resolved += 1;
 363→                    }
 364→                }
 365→                _ => {}
 366→            }
 367→        }
 368→
 369→        bg_launched > bg_resolved
 370→    }
 371→}
