 13→/// SessionInfo holds metadata about a discovered session file for the picker.
 14→#[derive(Debug, Clone, Serialize)]
 15→pub struct SessionInfo {
 16→    pub path: String,
 17→    pub session_id: String,
 18→    pub mod_time: DateTime<Utc>,
 19→    pub first_message: String,
 20→    pub turn_count: i32,
 21→    pub is_ongoing: bool,
 22→    pub total_tokens: i64,
 23→    pub input_tokens: i64,
 24→    pub output_tokens: i64,
 25→    pub cache_read_tokens: i64,
 26→    pub cache_creation_tokens: i64,
 27→    pub cost_usd: f64,
