 35→/// SessionMeta holds session-level metadata extracted from a JSONL file.
 36→#[derive(Debug, Clone, Default, Serialize)]
 37→pub struct SessionMeta {
 38→    pub cwd: String,
 39→    pub git_branch: String,
 40→    pub permission_mode: String,
 41→}
 42→
 43→/// Extract session metadata from a JSONL file.
 44→pub fn extract_session_meta(path: &str) -> SessionMeta {
 45→    let meta = scan_session_metadata(path);
 46→    SessionMeta {
 47→        cwd: meta.cwd,
 48→        git_branch: meta.git_branch,
 49→        permission_mode: meta.permission_mode,
 50→    }
 51→}
