143→/// Check if a directory entry is a session file (*.jsonl, not agent_*, not a directory).
144→fn is_session_file(name: &str, entry: &fs::DirEntry) -> bool {
145→    name.ends_with(".jsonl")
146→        && !name.starts_with("agent_")
147→        && !entry.file_type().map(|t| t.is_dir()).unwrap_or(true)
148→}
149→
150→/// Discover all session .jsonl files in a project directory.
151→pub fn discover_project_sessions(project_dir: &str) -> Result<Vec<SessionInfo>, String> {
152→    let entries = fs::read_dir(project_dir).map_err(|e| format!("reading {project_dir}: {e}"))?;
153→
154→    let mut sessions = Vec::new();
155→
156→    for entry in entries {
157→        let entry = match entry {
158→            Ok(e) => e,
159→            Err(_) => continue,
160→        };
161→        let name = entry.file_name().to_string_lossy().to_string();
162→        if !is_session_file(&name, &entry) {
163→            continue;
164→        }
165→
166→        let metadata = entry.metadata();
167→        let mod_time = metadata
168→            .as_ref()
169→            .ok()
170→            .and_then(|m| m.modified().ok())
171→            .map(DateTime::<Utc>::from)
172→            .unwrap_or_else(Utc::now);
173→
174→        let path = entry.path().to_string_lossy().to_string();
175→        let meta = scan_session_metadata(&path);
176→
177→        let mut is_ongoing = meta.is_ongoing;
178→        if is_ongoing {
179→            if let Ok(m) = entry.metadata() {
180→                if let Ok(modified) = m.modified() {
181→                    is_ongoing = super::ongoing::apply_staleness(true, modified);
182→                }
183→            }
184→        }
185→        if !is_ongoing {
186→            is_ongoing = super::subagent::has_recently_active_subagents(&path);
187→        }
188→
189→        let session_id = name.trim_end_matches(".jsonl").to_string();
190→
191→        sessions.push(SessionInfo {
192→            path,
193→            session_id,
194→            mod_time,
195→            first_message: meta.first_msg,
196→            turn_count: meta.turn_count,
197→            is_ongoing,
198→            total_tokens: meta.total_tokens,
199→            input_tokens: meta.input_tokens,
200→            output_tokens: meta.output_tokens,

 200→            output_tokens: meta.output_tokens,
 201→            cache_read_tokens: meta.cache_read_tokens,
 202→            cache_creation_tokens: meta.cache_creation_tokens,
 203→            cost_usd: meta.cost_usd,
 204→            duration_ms: meta.duration_ms,
 205→            model: meta.model,
 206→            cwd: meta.cwd,
 207→            git_branch: meta.git_branch,
 208→            permission_mode: meta.permission_mode,
 209→        });
 210→    }
 211→
 212→    sessions.sort_by(|a, b| b.mod_time.cmp(&a.mod_time));
 213→    Ok(sessions)
 214→}
 215→
 216→/// Discover sessions across multiple project directories.
 217→pub fn discover_all_project_sessions(project_dirs: &[String]) -> Result<Vec<SessionInfo>, String> {
 218→    let mut all = Vec::new();
 219→    for dir in project_dirs {
 220→        if let Ok(sessions) = discover_project_sessions(dir) {
 221→            all.extend(sessions);
 222→        }
 223→    }
 224→    all.sort_by(|a, b| b.mod_time.cmp(&a.mod_time));
 225→    Ok(all)
 226→}
