 235→    let mod_time_chrono: DateTime<Utc> = mod_time.into();
 236→    let mut is_ongoing = super::ongoing::apply_staleness(meta.is_ongoing, mod_time);
 237→    if !is_ongoing {
 238→        is_ongoing = super::subagent::has_recently_active_subagents(path);
