 267→/// Discover sessions using a custom scan function (for caching).
 268→pub fn discover_project_sessions_with_scan<F>(
 269→    project_dir: &str,
 270→    scan: F,
 271→) -> Result<Vec<SessionInfo>, String>
 272→where
 273→    F: Fn(&str, std::time::SystemTime, u64) -> Option<SessionInfo>,
 274→{
 275→    let entries = fs::read_dir(project_dir).map_err(|e| format!("reading {project_dir}: {e}"))?;
 276→
 277→    let mut sessions = Vec::new();
 278→
 279→    for entry in entries {
 280→        let entry = match entry {
 281→            Ok(e) => e,
 282→            Err(_) => continue,
 283→        };
 284→        let name = entry.file_name().to_string_lossy().to_string();
 285→        if !is_session_file(&name, &entry) {
 286→            continue;
 287→        }
 288→
 289→        let metadata = match entry.metadata() {
 290→            Ok(m) => m,
 291→            Err(_) => continue,
 292→        };
 293→        let mod_time = metadata.modified().unwrap_or(std::time::SystemTime::now());
 294→        let size = metadata.len();
 295→
 296→        let path = entry.path().to_string_lossy().to_string();
 297→        if let Some(info) = scan(&path, mod_time, size) {
 298→            sessions.push(info);
 299→        }
 300→    }
 301→
 302→    sessions.sort_by(|a, b| b.mod_time.cmp(&a.mod_time));
 303→    Ok(sessions)
 304→}
