 345→pub(crate) fn scan_session_metadata(path: &str) -> SessionMetadata {
 346→    use super::classify::parse_timestamp;
 347→    use super::patterns::RE_COMMAND_NAME;
 348→    use super::sanitize::{extract_text, is_command_output, sanitize_content};
 349→
 350→    let f = match fs::File::open(path) {
 351→        Ok(f) => f,
 352→        Err(_) => return SessionMetadata::default(),
 353→    };
 354→    let reader = BufReader::new(f);
 355→
 356→    let mut meta = SessionMetadata::default();
 357→    let mut command_fallback = String::new();
 358→    let mut preview_found = false;
 359→    let mut lines_read = 0;
 360→    const MAX_PREVIEW_LINES: usize = 200;
 361→
 362→    // Turn counting: user message increments, then first qualifying AI response increments.
 363→    let mut awaiting_ai_group = false;
 364→
 365→    // Token deduplication: track per-requestId usage, sum once at end.
 366→    use super::subagent::TokenSnapshot;
 367→    let mut request_tokens: HashMap<String, TokenSnapshot> = HashMap::new();
 368→
 369→    // Ongoing detection state (one-pass, ported from jsonl.ts).
 370→    let mut activity_index: usize = 0;
 371→    let mut last_ending_index: Option<usize> = None;
 372→    let mut has_any_ongoing_activity = false;
 373→    let mut has_activity_after_last_ending = false;
 374→    let mut shutdown_tool_ids: HashSet<String> = HashSet::new();
 375→    let mut pending_tool_ids: HashSet<String> = HashSet::new();
 376→
 377→    // Duration tracking.
 378→    let mut first_ts: Option<DateTime<Utc>> = None;
 379→    let mut last_ts: Option<DateTime<Utc>> = None;
 380→
 381→    for line_result in reader.lines() {
 382→        let line = match line_result {
 383→            Ok(l) => l,
 384→            Err(_) => break,
 385→        };
 386→        lines_read += 1;
 387→
 388→        let raw: Value = match serde_json::from_str(&line) {
 389→            Ok(v) => v,
 390→            Err(_) => continue,
 391→        };
 392→
 393→        let entry_type = raw.get("type").and_then(|v| v.as_str()).unwrap_or("");
 394→
 395→        // Track timestamps for duration (all entries, even UUID-less ones).
 396→        if let Some(ts_str) = raw.get("timestamp").and_then(|v| v.as_str()) {
 397→            let ts = parse_timestamp(ts_str);
 398→            if first_ts.is_none() {
 399→                first_ts = Some(ts);
 400→            }
 401→            last_ts = Some(ts);
 402→        }
 403→
 404→        // --- Session-level metadata (cwd, branch: first seen; mode: last seen) ---
 405→        // Extract before UUID check so queue-operation entries contribute metadata.
 406→        if meta.cwd.is_empty() {
 407→            if let Some(cwd) = raw.get("cwd").and_then(|v| v.as_str()) {
 408→                if !cwd.is_empty() {
 409→                    meta.cwd = cwd.to_string();
 410→                }
 411→            }
 412→        }
 413→        if meta.git_branch.is_empty() {
 414→            if let Some(branch) = raw.get("gitBranch").and_then(|v| v.as_str()) {
 415→                if !branch.is_empty() {
 416→                    meta.git_branch = branch.to_string();
 417→                }
 418→            }
 419→        }
 420→        if let Some(mode) = raw.get("permissionMode").and_then(|v| v.as_str()) {
 421→            if !mode.is_empty() {
 422→                meta.permission_mode = mode.to_string();
 423→            }
 424→        }
 425→
 426→        let uuid = raw.get("uuid").and_then(|v| v.as_str()).unwrap_or("");
 427→        if uuid.is_empty() {
 428→            continue;
 429→        }
 430→
 431→        let is_sidechain = raw
 432→            .get("isSidechain")
 433→            .and_then(|v| v.as_bool())
 434→            .unwrap_or(false);
 435→        let is_meta_flag = raw.get("isMeta").and_then(|v| v.as_bool()).unwrap_or(false);
 436→
 437→        // --- Turn counting (matches isParsedUserChunkMessage + AI pairing) ---
 438→        if is_user_chunk_for_turn_count(&raw, entry_type, is_meta_flag, is_sidechain) {
 439→            meta.turn_count += 1;
 440→            awaiting_ai_group = true;
 441→        } else if awaiting_ai_group && entry_type == "assistant" && !is_sidechain {
 442→            let model_str = raw
 443→                .get("message")
 444→                .and_then(|m| m.get("model"))
 445→                .and_then(|v| v.as_str())
 446→                .unwrap_or("");
 447→            if model_str != "<synthetic>" {
 448→                meta.turn_count += 1;
 449→                awaiting_ai_group = false;
 450→            }
 451→        }
 452→
 453→        // --- Token accumulation (dedup streaming entries by requestId) ---
 454→        // Include sidechain entries so cost reflects all API calls.
 455→        if entry_type == "assistant" {
 456→            let model_str = raw
 457→                .get("message")
 458→                .and_then(|m| m.get("model"))
 459→                .and_then(|v| v.as_str())
 460→                .unwrap_or("");
 461→            if model_str != "<synthetic>" {
 462→                if let Some(usage) = raw.get("message").and_then(|m| m.get("usage")) {
 463→                    let has_stop = !raw
 464→                        .get("message")
 465→                        .and_then(|m| m.get("stop_reason"))
 466→                        .and_then(|v| v.as_str())
 467→                        .unwrap_or("")
 468→                        .is_empty();
 469→
 470→                    let reported_output = usage
 471→                        .get("output_tokens")
 472→                        .and_then(|v| v.as_i64())
 473→                        .unwrap_or(0);
 474→
 475→                    // For incomplete streaming entries (no stop_reason), the
 476→                    // output_tokens may be frozen at an early value while
 477→                    // content continued to stream. Use a content-based
 478→                    // estimate when it exceeds the reported value.
 479→                    let output = if has_stop {
 480→                        reported_output
 481→                    } else {
 482→                        let estimated = super::subagent::estimate_output_from_content(&raw);
 483→                        reported_output.max(estimated)
 484→                    };
 485→
 486→                    let snap = TokenSnapshot {
 487→                        input: usage
 488→                            .get("input_tokens")
 489→                            .and_then(|v| v.as_i64())
 490→                            .unwrap_or(0),
 491→                        output,
 492→                        cache_read: usage
 493→                            .get("cache_read_input_tokens")
 494→                            .and_then(|v| v.as_i64())
 495→                            .unwrap_or(0),
 496→                        cache_create: usage
 497→                            .get("cache_creation_input_tokens")
 498→                            .and_then(|v| v.as_i64())
 499→                            .unwrap_or(0),
 500→                        model: model_str.to_string(),
 501→                        has_stop_reason: has_stop,
 502→                    };
 503→
 504→                    let request_id = raw.get("requestId").and_then(|v| v.as_str()).unwrap_or("");
 505→                    if !request_id.is_empty() {
 506→                        // Prefer complete entries over partial streaming snapshots.
 507→                        super::subagent::insert_best_snapshot(
 508→                            &mut request_tokens,
 509→                            request_id.to_string(),
 510→                            snap,
 511→                        );
 512→                    } else {
 513→                        // No requestId: sum directly.
 514→                        meta.total_tokens +=
 515→                            snap.input + snap.output + snap.cache_read + snap.cache_create;
 516→                        meta.input_tokens += snap.input;
 517→                        meta.output_tokens += snap.output;
 518→                        meta.cache_read_tokens += snap.cache_read;
 519→                        meta.cache_creation_tokens += snap.cache_create;
 520→                    }
 521→                }
 522→
 523→                // Model extraction (first real main-context assistant entry).
 524→                if !is_sidechain && meta.model.is_empty() && !model_str.is_empty() {
 525→                    meta.model = model_str.to_string();
 526→                }
 527→            }
 528→        }
 529→
 530→        // --- Ongoing detection ---
 531→        if entry_type == "assistant" && !is_sidechain {
 532→            scan_ongoing_assistant(
 533→                &raw,
 534→                &mut activity_index,
 535→                &mut last_ending_index,
 536→                &mut has_any_ongoing_activity,
 537→                &mut has_activity_after_last_ending,
 538→                &mut shutdown_tool_ids,
 539→                &mut pending_tool_ids,
 540→            );
 541→        } else if entry_type == "user" {
 542→            scan_ongoing_user(
 543→                &raw,
 544→                &mut activity_index,
 545→                &mut last_ending_index,
 546→                &mut has_any_ongoing_activity,
 547→                &mut has_activity_after_last_ending,
 548→                &mut shutdown_tool_ids,
 549→                &mut pending_tool_ids,
 550→            );
 551→        }
 552→
 553→        // --- Preview extraction ---
 554→        if preview_found || lines_read > MAX_PREVIEW_LINES || entry_type != "user" {
 555→            continue;
 556→        }
 557→
 558→        let content = raw.get("message").and_then(|m| m.get("content")).cloned();
 559→        let text = extract_text(&content);
 560→        if text.is_empty() {
 561→            continue;
 562→        }
 563→
 564→        if is_command_output(&text) || text.starts_with("[Request interrupted by user") {
 565→            continue;
 566→        }
 567→
 568→        if text.starts_with("<command-name>") {
 569→            if command_fallback.is_empty() {
 570→                if let Some(caps) = RE_COMMAND_NAME.captures(&text) {
 571→                    command_fallback =
 572→                        format!("/{}", caps.get(1).map_or("command", |m| m.as_str()).trim());
 573→                } else {
 574→                    command_fallback = "/command".to_string();
 575→                }
 576→            }
 577→            continue;
 578→        }
 579→
 580→        let sanitized = sanitize_content(&text);
 581→        let sanitized = sanitized.trim();
 582→        if !sanitized.is_empty() {
 583→            let msg: String = sanitized.chars().take(500).collect();
 584→            meta.first_msg = msg;
 585→            preview_found = true;
 586→        }
 587→    }
 588→
 589→    if meta.first_msg.is_empty() {
 590→        meta.first_msg = command_fallback;
 591→    }
 592→    if !meta.first_msg.is_empty() {
 593→        meta.first_msg = meta.first_msg.replace('\n', " ");
 594→    }
 595→    if meta.permission_mode.is_empty() {
 596→        meta.permission_mode = "default".to_string();
 597→    }
 598→
 599→    // Scan subagent JSONL files into the same request_tokens map (global requestId dedup).
 600→    let mut fallback = TokenSnapshot {
 601→        input: 0,
 602→        output: 0,
 603→        cache_read: 0,
 604→        cache_create: 0,
 605→        model: String::new(),
 606→        has_stop_reason: false,
 607→    };
 608→    super::subagent::scan_subagent_tokens_into(path, &mut request_tokens, &mut fallback);
 609→    meta.total_tokens +=
 610→        fallback.input + fallback.output + fallback.cache_read + fallback.cache_create;
 611→    meta.input_tokens += fallback.input;
 612→    meta.output_tokens += fallback.output;
 613→    meta.cache_read_tokens += fallback.cache_read;
 614→    meta.cache_creation_tokens += fallback.cache_create;
 615→
 616→    // Finalize token totals: sum the last-seen usage per requestId.
 617→    for snap in request_tokens.values() {
 618→        meta.total_tokens += snap.input + snap.output + snap.cache_read + snap.cache_create;
 619→        meta.input_tokens += snap.input;
 620→        meta.output_tokens += snap.output;
 621→        meta.cache_read_tokens += snap.cache_read;
 622→        meta.cache_creation_tokens += snap.cache_create;
 623→    }
 624→
 625→    // Compute cost per-model (accurate for mixed opus/haiku/sonnet sessions).
 626→    meta.cost_usd = super::subagent::estimate_cost_from_snapshots(&request_tokens, &fallback);
 627→
 628→    // Finalize ongoing detection.
 629→    if last_ending_index.is_none() {
 630→        meta.is_ongoing = has_any_ongoing_activity;
 631→    } else {
 632→        meta.is_ongoing = has_activity_after_last_ending;
 633→    }
 634→    // Pending tool calls override.
 635→    if !meta.is_ongoing && !pending_tool_ids.is_empty() {
 636→        meta.is_ongoing = true;
 637→    }
 638→
 639→    // Finalize duration.
 640→    if let (Some(first), Some(last)) = (first_ts, last_ts) {
 641→        meta.duration_ms = last.signed_duration_since(first).num_milliseconds();
 642→    }
 643→
 644→    meta
 645→}
 646→
 647→/// Incremental token scanner for the watcher — avoids re-reading the entire file.
 648→///
 649→/// Keeps a running `request_tokens` map and byte offset so that each call to
 650→/// `scan_new_bytes` only reads the newly appended portion of the main session
 651→/// file. Subagent files are rescanned only when their size changes.
 652→pub struct IncrementalTokenScanner {
 653→    /// Byte offset into the main session file (how far we've read).
 654→    offset: u64,
 655→    /// Per-requestId best token snapshot (global dedup across main + subagents).
 656→    request_tokens: HashMap<String, super::subagent::TokenSnapshot>,
 657→    /// Accumulated tokens from entries without a requestId.
 658→    fallback: super::subagent::TokenSnapshot,
 659→    /// Model string (first real non-sidechain assistant model).
 660→    model: String,
 661→    /// Cached subagent file sizes — only rescan files that grew.
 662→    subagent_sizes: HashMap<String, u64>,
 663→    /// Per-subagent byte offsets for incremental reading.
 664→    subagent_offsets: HashMap<String, u64>,
 665→}
 666→
 667→impl IncrementalTokenScanner {
 668→    pub fn new() -> Self {
 669→        Self {
 670→            offset: 0,
 671→            request_tokens: HashMap::new(),
 672→            fallback: super::subagent::TokenSnapshot {
 673→                input: 0,
 674→                output: 0,
 675→                cache_read: 0,
 676→                cache_create: 0,
 677→                model: String::new(),
 678→                has_stop_reason: false,
 679→            },
 680→            model: String::new(),
 681→            subagent_sizes: HashMap::new(),
 682→            subagent_offsets: HashMap::new(),
 683→        }
 684→    }
 685→
 686→    /// Scan only new bytes from the main session file and any changed subagent files.
 687→    /// Returns the current totals.
 688→    pub fn scan_new_bytes(&mut self, path: &str) -> crate::convert::SessionTotals {
 689→        // 1. Read new bytes from main session file.
 690→        self.scan_main_file(path);
 691→
 692→        // 2. Incrementally scan subagent files (only changed ones).
 693→        self.scan_subagents_incremental(path);
 694→
 695→        // 3. Compute totals from accumulated state.
 696→        self.compute_totals()
 697→    }
 698→
 699→    fn scan_main_file(&mut self, path: &str) {
 700→        let f = match fs::File::open(path) {
 701→            Ok(f) => f,
 702→            Err(_) => return,
 703→        };
 704→        let mut reader = BufReader::new(f);
 705→        if reader.seek(SeekFrom::Start(self.offset)).is_err() {
 706→            return;
 707→        }
 708→
 709→        let mut line = String::new();
 710→        loop {
 711→            line.clear();
 712→            let n = match reader.read_line(&mut line) {
 713→                Ok(n) => n,
 714→                Err(_) => break,
 715→            };
 716→            if n == 0 {
 717→                break;
 718→            }
 719→            self.offset += n as u64;
 720→            self.process_line(line.trim(), false);
 721→        }
 722→    }
 723→
 724→    fn scan_subagents_incremental(&mut self, session_path: &str) {
 725→        let dir = super::subagent::subagents_dir(session_path);
 726→        let entries = match fs::read_dir(&dir) {
 727→            Ok(e) => e,
 728→            Err(_) => return,
 729→        };
 730→
 731→        for entry in entries.flatten() {
 732→            let name = entry.file_name().to_string_lossy().to_string();
 733→            if !name.starts_with("agent-") || !name.ends_with(".jsonl") {
 734→                continue;
 735→            }
 736→            let file_path = dir.join(&name);
 737→            let key = file_path.to_string_lossy().to_string();
 738→
 739→            // Check if file has grown since last scan.
 740→            let current_size = entry.metadata().map(|m| m.len()).unwrap_or(0);
 741→            let prev_size = self.subagent_sizes.get(&key).copied().unwrap_or(0);
 742→            if current_size <= prev_size {
 743→                continue;
 744→            }
 745→            self.subagent_sizes.insert(key.clone(), current_size);
 746→
 747→            // Read from where we left off.
 748→            let sub_offset = self.subagent_offsets.get(&key).copied().unwrap_or(0);
 749→            let f = match fs::File::open(&file_path) {
 750→                Ok(f) => f,
 751→                Err(_) => continue,
 752→            };
 753→            let mut reader = BufReader::new(f);
 754→            if reader.seek(SeekFrom::Start(sub_offset)).is_err() {
 755→                continue;
 756→            }
 757→
 758→            let mut new_offset = sub_offset;
 759→            let mut line = String::new();
 760→            loop {
 761→                line.clear();
 762→                let n = match reader.read_line(&mut line) {
 763→                    Ok(n) => n,
 764→                    Err(_) => break,
 765→                };
 766→                if n == 0 {
 767→                    break;
 768→                }
 769→                new_offset += n as u64;
 770→                self.process_line(line.trim(), true);
 771→            }
 772→            self.subagent_offsets.insert(key, new_offset);
 773→        }
 774→    }
 775→
 776→    fn process_line(&mut self, line: &str, _is_subagent: bool) {
 777→        let raw: Value = match serde_json::from_str(line) {
 778→            Ok(v) => v,
 779→            Err(_) => return,
 780→        };
 781→
 782→        let entry_type = raw.get("type").and_then(|v| v.as_str()).unwrap_or("");
 783→        if entry_type != "assistant" {
 784→            return;
 785→        }
 786→
 787→        let model_str = raw
 788→            .get("message")
 789→            .and_then(|m| m.get("model"))
 790→            .and_then(|v| v.as_str())
 791→            .unwrap_or("");
 792→        if model_str == "<synthetic>" {
 793→            return;
 794→        }
 795→
 796→        let usage = match raw.get("message").and_then(|m| m.get("usage")) {
 797→            Some(u) => u,
 798→            None => return,
 799→        };
 800→
 801→        let has_stop = !raw
 802→            .get("message")
 803→            .and_then(|m| m.get("stop_reason"))
 804→            .and_then(|v| v.as_str())
 805→            .unwrap_or("")
 806→            .is_empty();
 807→
 808→        let reported_output = usage
 809→            .get("output_tokens")
 810→            .and_then(|v| v.as_i64())
 811→            .unwrap_or(0);
 812→
 813→        let output = if has_stop {
 814→            reported_output
 815→        } else {
 816→            let estimated = super::subagent::estimate_output_from_content(&raw);
 817→            reported_output.max(estimated)
 818→        };
 819→
 820→        let inp = usage
 821→            .get("input_tokens")
 822→            .and_then(|v| v.as_i64())
 823→            .unwrap_or(0);
 824→        let cr = usage
 825→            .get("cache_read_input_tokens")
 826→            .and_then(|v| v.as_i64())
 827→            .unwrap_or(0);
 828→        let cc = usage
 829→            .get("cache_creation_input_tokens")
 830→            .and_then(|v| v.as_i64())
 831→            .unwrap_or(0);
 832→
 833→        if inp + output + cr + cc == 0 {
 834→            return;
 835→        }
 836→
 837→        let snap = super::subagent::TokenSnapshot {
 838→            input: inp,
 839→            output,
 840→            cache_read: cr,
 841→            cache_create: cc,
 842→            model: model_str.to_string(),
 843→            has_stop_reason: has_stop,
 844→        };
 845→
 846→        let request_id = raw.get("requestId").and_then(|v| v.as_str()).unwrap_or("");
 847→        if !request_id.is_empty() {
 848→            super::subagent::insert_best_snapshot(
 849→                &mut self.request_tokens,
 850→                request_id.to_string(),
 851→                snap,
 852→            );
 853→        } else {
 854→            self.fallback.input += inp;
 855→            self.fallback.output += output;
 856→            self.fallback.cache_read += cr;
 857→            self.fallback.cache_create += cc;
 858→        }
 859→
 860→        // Capture model from first real entry.
 861→        if self.model.is_empty() && !model_str.is_empty() {
 862→            self.model = model_str.to_string();
 863→        }
 864→    }
 865→
 866→    fn compute_totals(&self) -> crate::convert::SessionTotals {
 867→        let mut total_tokens = self.fallback.input
 868→            + self.fallback.output
 869→            + self.fallback.cache_read
 870→            + self.fallback.cache_create;
 871→        let mut input_tokens = self.fallback.input;
 872→        let mut output_tokens = self.fallback.output;
 873→        let mut cache_read_tokens = self.fallback.cache_read;
 874→        let mut cache_creation_tokens = self.fallback.cache_create;
 875→
 876→        for snap in self.request_tokens.values() {
 877→            total_tokens += snap.input + snap.output + snap.cache_read + snap.cache_create;
 878→            input_tokens += snap.input;
 879→            output_tokens += snap.output;
 880→            cache_read_tokens += snap.cache_read;
 881→            cache_creation_tokens += snap.cache_create;
 882→        }
 883→
 884→        let cost_usd =
 885→            super::subagent::estimate_cost_from_snapshots(&self.request_tokens, &self.fallback);
 886→
 887→        crate::convert::SessionTotals {
 888→            total_tokens,
 889→            input_tokens,
 890→            output_tokens,
 891→            cache_read_tokens,
 892→            cache_creation_tokens,
 893→            cost_usd,
 894→            model: self.model.clone(),
 895→        }
 896→    }
 897→}
