 899→/// Mirrors claude-devtools' isParsedUserChunkMessage.
 900→fn is_user_chunk_for_turn_count(
 901→    raw: &Value,
 902→    entry_type: &str,
 903→    is_meta: bool,
 904→    is_sidechain: bool,
 905→) -> bool {
 906→    use super::classify::SYSTEM_OUTPUT_TAGS;
 907→    use super::patterns::TEAMMATE_MESSAGE_RE;
 908→    use super::sanitize::extract_text;
 909→
 910→    if entry_type != "user" || is_meta || is_sidechain {
 911→        return false;
 912→    }
 913→
 914→    let content = raw.get("message").and_then(|m| m.get("content")).cloned();
 915→    let text = extract_text(&content);
 916→    let trimmed = text.trim();
 917→
 918→    // Teammate messages.
 919→    if TEAMMATE_MESSAGE_RE.is_match(trimmed) {
 920→        return false;
 921→    }
 922→
 923→    // System output tags.
 924→    for tag in SYSTEM_OUTPUT_TAGS {
 925→        if trimmed.starts_with(tag) {
 926→            return false;
 927→        }
 928→    }
 929→
 930→    // Must have actual content.
 931→    has_user_content_raw(&content, &text)
 932→}
 933→
 934→fn has_user_content_raw(raw: &Option<Value>, str_content: &str) -> bool {
 935→    match raw {
 936→        Some(Value::String(_)) => !str_content.trim().is_empty(),
 937→        Some(Value::Array(blocks)) => blocks.iter().any(|b| {
 938→            let bt = b.get("type").and_then(|v| v.as_str()).unwrap_or("");
 939→            bt == "text" || bt == "image"
 940→        }),
 941→        _ => false,
 942→    }
 943→}
