 945→/// Process an assistant entry for ongoing detection (ported from jsonl.ts:438-470).
 946→fn scan_ongoing_assistant(
 947→    raw: &Value,
 948→    activity_index: &mut usize,
 949→    last_ending_index: &mut Option<usize>,
 950→    has_any: &mut bool,
 951→    has_after: &mut bool,
 952→    shutdown_ids: &mut HashSet<String>,
 953→    pending_tool_ids: &mut HashSet<String>,
 954→) {
 955→    use super::ongoing::is_shutdown_approval;
 956→
 957→    let blocks = match raw
 958→        .get("message")
 959→        .and_then(|m| m.get("content"))
 960→        .and_then(|c| c.as_array())
 961→    {
 962→        Some(b) => b,
 963→        None => return,
 964→    };
 965→
 966→    for b in blocks {
 967→        let bt = b.get("type").and_then(|v| v.as_str()).unwrap_or("");
 968→        match bt {
 969→            "thinking" => {
 970→                let thinking = b.get("thinking").and_then(|v| v.as_str()).unwrap_or("");
 971→                if !thinking.trim().is_empty() {
 972→                    *has_any = true;
 973→                    if last_ending_index.is_some() {
 974→                        *has_after = true;
 975→                    }
 976→                    *activity_index += 1;
 977→                }
 978→            }
 979→            "tool_use" => {
 980→                let id = b
 981→                    .get("id")
 982→                    .and_then(|v| v.as_str())
 983→                    .unwrap_or("")
 984→                    .to_string();
 985→                if id.is_empty() {
 986→                    continue;
 987→                }
 988→                let name = b
 989→                    .get("name")
 990→                    .and_then(|v| v.as_str())
 991→                    .unwrap_or("")
 992→                    .to_string();
 993→
 994→                if name == "ExitPlanMode" {
 995→                    *last_ending_index = Some(*activity_index);
 996→                    *has_after = false;
 997→                    *activity_index += 1;
 998→                } else if is_shutdown_approval(&name, &b.get("input").cloned()) {
 999→                    shutdown_ids.insert(id);
1000→                    *last_ending_index = Some(*activity_index);
1001→                    *has_after = false;
1002→                    *activity_index += 1;
1003→                } else {
1004→                    pending_tool_ids.insert(id);
1005→                    *has_any = true;
1006→                    if last_ending_index.is_some() {
1007→                        *has_after = true;
1008→                    }
1009→                    *activity_index += 1;
1010→                }
1011→            }
1012→            "text" => {
1013→                let text = b.get("text").and_then(|v| v.as_str()).unwrap_or("");
1014→                if !text.trim().is_empty() {
1015→                    *last_ending_index = Some(*activity_index);
1016→                    *has_after = false;
1017→                    *activity_index += 1;
1018→                }
1019→            }
1020→            _ => {}
1021→        }
1022→    }
1023→}
1024→
1025→/// Process a user entry for ongoing detection (ported from jsonl.ts:471-499).
1026→fn scan_ongoing_user(
1027→    raw: &Value,
1028→    activity_index: &mut usize,
1029→    last_ending_index: &mut Option<usize>,
1030→    has_any: &mut bool,
1031→    has_after: &mut bool,
1032→    shutdown_ids: &mut HashSet<String>,
1033→    pending_tool_ids: &mut HashSet<String>,
1034→) {
1035→    // Check for user-rejected tool use at the entry level.
1036→    let is_rejection = is_tool_use_rejection(raw);
1037→
1038→    // String-content user entries (e.g. "[Request interrupted by user...]").
1039→    let content = raw.get("message").and_then(|m| m.get("content"));
1040→    if let Some(Value::String(text)) = content {
1041→        if text.starts_with("[Request interrupted by user") {
1042→            pending_tool_ids.clear();
1043→            *last_ending_index = Some(*activity_index);
1044→            *has_after = false;
1045→            *activity_index += 1;
1046→        }
1047→        return;
1048→    }
1049→
1050→    let blocks = match content.and_then(|c| c.as_array()) {
1051→        Some(b) => b,
1052→        None => return,
1053→    };
1054→
1055→    for b in blocks {
1056→        let bt = b.get("type").and_then(|v| v.as_str()).unwrap_or("");
1057→        match bt {
1058→            "tool_result" => {
1059→                let tool_use_id = b
1060→                    .get("tool_use_id")
1061→                    .and_then(|v| v.as_str())
1062→                    .unwrap_or("")
1063→                    .to_string();
1064→                if tool_use_id.is_empty() {
1065→                    continue;
1066→                }
1067→                pending_tool_ids.remove(&tool_use_id);
1068→                if shutdown_ids.contains(&tool_use_id) || is_rejection {
1069→                    // Ending event.
1070→                    *last_ending_index = Some(*activity_index);
1071→                    *has_after = false;
1072→                    *activity_index += 1;
1073→                } else {
1074→                    // Ongoing activity.
1075→                    *has_any = true;
1076→                    if last_ending_index.is_some() {
1077→                        *has_after = true;
1078→                    }
1079→                    *activity_index += 1;
1080→                }
1081→            }
1082→            "text" => {
1083→                let text = b.get("text").and_then(|v| v.as_str()).unwrap_or("");
1084→                if text.starts_with("[Request interrupted by user") {
1085→                    pending_tool_ids.clear();
1086→                    *last_ending_index = Some(*activity_index);
1087→                    *has_after = false;
1088→                    *activity_index += 1;
1089→                }
1090→            }
1091→            _ => {}
1092→        }
1093→    }
1094→}
