1214→        let complete = r#"{"type":"assistant","uuid":"a2","requestId":"r1","message":{"model":"claude-sonnet-4-20250514","role":"assistant","content":[],"usage":{"input_tokens":100,"output_tokens":50,"cache_read_input_tokens":0,"cache_creation_input_tokens":0},"stop_reason":"end_turn"}}"#;
1215→        std::fs::write(&path, format!("{streaming}\n{complete}\n")).unwrap();
1216→
1217→        let mut scanner = IncrementalTokenScanner::new();
1218→        let totals = scanner.scan_new_bytes(path.to_str().unwrap());
1219→        // Should use the complete entry (50 output), not streaming (20).
1220→        assert_eq!(totals.input_tokens, 100);
1221→        assert_eq!(totals.output_tokens, 50);
1222→        assert_eq!(totals.total_tokens, 150);
1223→
1224→        std::fs::remove_dir_all(&tmp).ok();
1225→    }
1226→
1227→    #[test]
1228→    fn incremental_scanner_skips_non_assistant_lines() {
1229→        let tmp = env::temp_dir().join("tail-test-scanner-skip");
1230→        std::fs::create_dir_all(&tmp).unwrap();
1231→        let path = tmp.join("session.jsonl");
1232→
1233→        let user_entry = r#"{"type":"user","uuid":"u1","message":{"content":"hello"}}"#;
1234→        let assistant_entry = r#"{"type":"assistant","uuid":"a1","requestId":"r1","message":{"model":"claude-sonnet-4-20250514","role":"assistant","content":[],"usage":{"input_tokens":50,"output_tokens":25,"cache_read_input_tokens":0,"cache_creation_input_tokens":0},"stop_reason":"end_turn"}}"#;
1235→        std::fs::write(&path, format!("{user_entry}\n{assistant_entry}\n")).unwrap();
1236→
1237→        let mut scanner = IncrementalTokenScanner::new();
1238→        let totals = scanner.scan_new_bytes(path.to_str().unwrap());
1239→        assert_eq!(totals.total_tokens, 75);
1240→
1241→        std::fs::remove_dir_all(&tmp).ok();
1242→    }
1243→}
