138→fn apply_team_task_update(input: &Option<Value>, team: &mut TeamSnapshot) {
139→    let task_id = get_single_field(input, "taskId");
140→    if task_id.is_empty() {
141→        return;
142→    }
143→    for task in &mut team.tasks {
144→        if task.id != task_id {
145→            continue;
146→        }
147→        let status = get_single_field(input, "status");
148→        if !status.is_empty() {
149→            task.status = status;
150→        }
151→        let owner = get_single_field(input, "owner");
152→        if !owner.is_empty() {
153→            task.owner = owner;
154→        }
155→        let subject = get_single_field(input, "subject");
156→        if !subject.is_empty() {
157→            task.subject = subject;
158→        }
159→        return;
160→    }
161→}
162→
163→fn add_team_spawn_member(input: &Option<Value>, teams: &mut [TeamSnapshot]) {
164→    let (team_name, member_name) = get_string_fields(input, "team_name", "name");
165→    if team_name.is_empty() || member_name.is_empty() {
166→        return;
167→    }
168→    for team in teams.iter_mut() {
169→        if team.name != team_name {
170→            continue;
171→        }
172→        if !team.members.contains(&member_name) {
173→            team.members.push(member_name);
174→        }
175→        return;
176→    }
177→}
