110→/// Format a timestamp as "yyyy-mm-dd hh:mm:ss".
111→fn format_time(ts: &chrono::DateTime<chrono::Utc>) -> String {
112→    use chrono::Local;
113→    let local = ts.with_timezone(&Local);
114→    local.format("%Y-%m-%d %H:%M:%S").to_string()
115→}
