427→/// Check if any chunk contains team Task items.
428→pub fn has_team_task_items(chunks: &[Chunk]) -> bool {
429→    for c in chunks {
430→        for item in &c.items {
431→            if item.item_type == DisplayItemType::Subagent && is_team_task(item) {
432→                return true;
433→            }
434→        }
435→    }
436→    false
