 88→/// Return all project directories under the Claude projects base directory.
 89→/// Each subdirectory corresponds to an encoded project path.
 90→#[tauri::command]
 91→pub async fn get_project_dirs(state: State<'_, AppState>) -> Result<Vec<String>, String> {
 92→    let configured = state
 93→        .settings
 94→        .lock()
 95→        .map_err(|e| e.to_string())?
 96→        .projects_dir
 97→        .clone();
 98→    let projects_dir = crate::parser::session::claude_projects_dir(configured.as_deref())?;
 99→    if !projects_dir.exists() {
100→        return Ok(Vec::new());
101→    }
102→    let mut dirs = Vec::new();
103→    let entries = std::fs::read_dir(&projects_dir).map_err(|e| e.to_string())?;
104→    for entry in entries.flatten() {
105→        if entry.file_type().map(|t| t.is_dir()).unwrap_or(false) {
106→            dirs.push(entry.path().to_string_lossy().to_string());
107→        }
108→    }
109→    Ok(dirs)
110→}
