 952→/// Returns true if any subagent JSONL file was recently modified (within staleness threshold).
 953→pub fn has_recently_active_subagents(session_path: &str) -> bool {
 954→    let dir = subagents_dir(session_path);
 955→    let entries = match fs::read_dir(&dir) {
 956→        Ok(e) => e,
 957→        Err(_) => return false,
 958→    };
 959→    for entry in entries.flatten() {
 960→        let name = entry.file_name().to_string_lossy().to_string();
 961→        if !name.starts_with("agent-") || !name.ends_with(".jsonl") {
 962→            continue;
 963→        }
 964→        if let Ok(meta) = entry.metadata() {
 965→            if let Ok(modified) = meta.modified() {
 966→                if super::ongoing::apply_staleness(true, modified) {
 967→                    return true;
 968→                }
 969→            }
 970→        }
 971→    }
 972→    false
 973→}
