 991→        if !name.starts_with("agent-") || !name.ends_with(".jsonl") {
 992→            continue;
 993→        }
 994→        // Include compact files — they contain requestIds from compacted
 995→        // conversation data that may no longer be in the main session file.
 996→        let file_path = dir.join(&name);
 997→        let f = match fs::File::open(&file_path) {
 998→            Ok(f) => f,
 999→            Err(_) => continue,
1000→        };
1001→        let reader = BufReader::new(f);
1002→        for line_result in reader.lines() {
