1014→            }
1015→            let model = raw
1016→                .get("message")
1017→                .and_then(|m| m.get("model"))
1018→                .and_then(|v| v.as_str())
1019→                .unwrap_or("");
1020→            if model == "<synthetic>" {
1021→                continue;
1022→            }
1023→            let usage = match raw.get("message").and_then(|m| m.get("usage")) {
1024→                Some(u) => u,
1025→                None => continue,
1026→            };
1027→            let inp = usage
1028→                .get("input_tokens")
1029→                .and_then(|v| v.as_i64())
1030→                .unwrap_or(0);
1031→            let out = usage
1032→                .get("output_tokens")
1033→                .and_then(|v| v.as_i64())
1034→                .unwrap_or(0);
1035→            let cr = usage
1036→                .get("cache_read_input_tokens")
1037→                .and_then(|v| v.as_i64())
1038→                .unwrap_or(0);
